mapper.select:
/* [selectSysCodeDetailData] 시스템코드관리 화면의 상세 코드 조회 */ SELECT AA.ROW_NUMBER , AA.GROUP_CODE , AA.CODE_SECTION_CODE , AA.CODE , AA.CODE_NAME , AA.CODE_DESC , BB.CHANGE_DATA_LIST , AA.ETC_01_INFO , AA.ETC_02_INFO , AA.ETC_03_INFO , AA.ETC_04_INFO , AA.ETC_05_INFO , AA.ETC_06_INFO , AA.ETC_07_INFO , AA.ETC_08_INFO , AA.ETC_09_INFO , AA.ETC_10_INFO , AA.BEGIN_DATE , AA.END_DATE , AA.SORTING_SN , AA.USE_AT_NAME , AA.USE_AT , AA.FIRST_CREATE_USER_NAME , AA.FIRST_CREATE_USER_ID , AA.LAST_UPDATE_USER_NAME , AA.LAST_UPDATE_USER_ID , AA.CREATE_DT , AA.UPDATE_DT FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.SORTING_SN, A.GROUP_CODE) AS ROW_NUMBER , A.GROUP_CODE --그룹코드 , A.CODE_SECTION_CODE --코드구분코드 , A.CODE --코드 , A.CODE_NAME , A.CODE_DESC , A.ETC_01_INFO --기타 01 정보 , A.ETC_02_INFO --기타 02 정보 , A.ETC_03_INFO --기타 03 정보 , A.ETC_04_INFO --기타 04 정보 , A.ETC_05_INFO --기타 05 정보 , A.ETC_06_INFO --기타 06 정보 , A.ETC_07_INFO --기타 07 정보 , A.ETC_08_INFO --기타 08 정보 , A.ETC_09_INFO --기타 09 정보 , A.ETC_10_INFO --기타 10 정보 , A.BEGIN_DATE --코드적용일자 , A.END_DATE --코드종료일자 , A.SORTING_SN --정렬순번 , CASE WHEN A.USE_AT = 'Y' THEN '사용' ELSE '미사용' END AS USE_AT_NAME --사용여부명 , A.USE_AT --사용여부 , COALESCE(B.USER_NAME, A.FIRST_CREATE_USER_ID) AS FIRST_CREATE_USER_NAME --최초생성자명 , A.FIRST_CREATE_USER_ID --최초생성자ID , COALESCE(C.USER_NAME, A.LAST_UPDATE_USER_ID) AS LAST_UPDATE_USER_NAME --최종수정자명 , A.LAST_UPDATE_USER_ID --최종수정자ID , A.CREATE_DT --최초생성일시 , A.UPDATE_DT --최종수정일시 FROM VIEW_COM_SYS_CODE A LEFT OUTER JOIN COM_USER B ON A.FIRST_CREATE_USER_ID = B.USER_ID AND B.COMPANY_CODE = #{sessionCompanyCode} LEFT OUTER JOIN COM_USER C ON A.LAST_UPDATE_USER_ID = C.USER_ID AND C.COMPANY_CODE = #{sessionCompanyCode} WHERE 1=1 AND A.LANGUAGE_CODE = #{sessionLanguageCode} AND A.CODE != '*****' AND A.GROUP_CODE = #{groupCode}
AND A.USE_AT = #{searchUseAtDetail}
AND A.USE_AT = #{useAt}
GROUP BY A.GROUP_CODE , A.CODE_SECTION_CODE , A.CODE , A.CODE_NAME , A.CODE_DESC , A.ETC_01_INFO , A.ETC_02_INFO , A.ETC_03_INFO , A.ETC_04_INFO , A.ETC_05_INFO , A.ETC_06_INFO , A.ETC_07_INFO , A.ETC_08_INFO , A.ETC_09_INFO , A.ETC_10_INFO , A.BEGIN_DATE , A.END_DATE , A.SORTING_SN , A.USE_AT , A.FIRST_CREATE_USER_ID , A.LAST_UPDATE_USER_ID , A.CREATE_DT , A.UPDATE_DT , B.USER_NAME , C.USER_NAME ) AA LEFT OUTER JOIN ( SELECT STRING_AGG( ( A.LANGUAGE_CODE || '###' || COALESCE(A.CODE_NAME,'') || '###' || COALESCE(A.CODE_DESC,'') ), '%%') AS CHANGE_DATA_LIST , A.CODE , A.GROUP_CODE FROM VIEW_COM_SYS_CODE A WHERE A.CODE != '*****' AND A.GROUP_CODE = #{groupCode} AND A.LANGUAGE_CODE IN ( SELECT CODE FROM COM_SYS_CODE WHERE GROUP_CODE = 'SYS028' -- 사용여부가 Y인 다국어 언어만 보이도록 AND CODE != '*****' AND USE_AT = 'Y' ) GROUP BY A.GROUP_CODE, A.CODE ) BB ON AA.GROUP_CODE = BB.GROUP_CODE AND AA.CODE = BB.CODE ORDER BY AA.GROUP_CODE , AA.SORTING_SN

/* [selectCompanyByKey] 회사의 암호화 키 정보 조회 */
SELECT ENCPT_KEY_INFO
  FROM COM_COMPANY
 WHERE COMPANY_CODE = #{companyCode}

mapper.update:
/* [updateUser] 사용자정보 수정 */
UPDATE COM_USER
   SET UPDATE_DT                     = CURRENT_TIMESTAMP

     , LAST_UPDATE_USER_ID           = 'SYSTEM'


     , LAST_UPDATE_USER_ID           = #{sessionUserId}


     , PASSWORD_ENCPT                = #{passwordEncpt}


     , EMP_NUMBER                    = #{empNumber}


     , USER_NAME                     = #{userName}


     , MOBILE_PHONE_KEY              = #{mobilePhoneKey}


     , MOBILE_PHONE_MASK             = #{mobilePhoneMask}


     , MOBILE_PHONE_ENCPT            = #{mobilePhoneEncpt}


     , CABLETELEPHONE_KEY            = #{cabletelephoneKey}


     , CABLETELEPHONE_MASK           = #{cabletelephoneMask}


     , CABLETELEPHONE_ENCPT          = #{cabletelephoneEncpt}


     , EMAIL_KEY                     = #{emailKey}


     , EMAIL_MASK                    = #{emailMask}


     , EMAIL_ENCPT                   = #{emailEncpt}


     , DEPT_CODE                     = #{deptCode}


     , RSPOFC_CODE                   = #{rspofcCode}


     , WORK_SECTION_CODE             = #{workSectionCode}


     , IMAGE_FILE_GROUP_KEY          = #{imageFileGroupKey}


     , ETC_01_INFO                   = #{etc01Info}


     , ETC_02_INFO                   = #{etc02Info}


     , ETC_03_INFO                   = #{etc03Info}


     , ETC_04_INFO                   = #{etc04Info}


     , ETC_05_INFO                   = #{etc05Info}


     , ACCOUNT_USE_AT                = #{accountUseAt}


     , PASSWORD_ERROR_COUNT          = #{passwordErrorCount}


     , LOGIN_AT                      = #{loginAt}


     , ENTRANCE_COMPANY_DATE         = #{EntranceCompanyDate}


     , RETIRE_DATE                   = #{retireDate}


     , RETIRE_REASON_CONTENTS        = #{retireReasonContents}


     , RECENT_LOGIN_DT               = CURRENT_TIMESTAMP AT TIME ZONE 'UTC'


     , RECENT_LOGOUT_DT              = TO_TIMESTAMP(#{recentLogoutDt}, 'YYYY-MM-DD HH24:MI:SS.FF') AT TIME ZONE 'UTC'


     , RECENT_CONNECT_IP             = #{recentConnectIp}


     , RECENT_CONNECT_SESSION_ID_INFO= #{recentConnectSessionIdInfo}


     , CTI_ID                        = #{ctiId}


     , VPN_ID                        = #{vpnId}


     , LOCAL_EXTENTION_NUMBER        = #{localExtentionNumber}


     , EXTERNAL_NUMBER               = #{externalNumber}


     , VO_IP                         = #{voIp}


     , NAT_IP                        = #{natIp}


     , PC_IP                         = #{pcIp}


     , VPN_IP                        = #{vpnIp}

 WHERE COMPANY_CODE                  = #{companyCode}
   AND USER_ID                       = #{userId}

